mapper.select:
/* DisMgmtMapper.selectChrgListExcel */ SELECT A.PRMT_ID AS PRMT_ID , A.PRMT_NM AS PRMT_NM , A.STRT_DT AS STRT_DT , A.END_DT AS END_DT , A.NAC_YN AS NAC_YN , A.MNP_YN AS MNP_YN , A.ORGN_TYPE AS ORGN_TYPE , FN_GET_CODENM('CMN0055', A.ORGN_TYPE) AS ORGN_TYPE_NM , A.REQ_BUY_TYPE AS REQ_BUY_TYPE , FN_GET_CODENM('RCP9022', A.REQ_BUY_TYPE) AS REQ_BUY_TYPE_NM , A.ENGG_CNT_0 AS ENGG_CNT0 , A.ENGG_CNT_12 AS ENGG_CNT12 , A.ENGG_CNT_18 AS ENGG_CNT18 , A.ENGG_CNT_24 AS ENGG_CNT24 , A.ENGG_CNT_30 AS ENGG_CNT30 , A.ENGG_CNT_36 AS ENGG_CNT36 , A.USG_YN AS USG_YN , A.REGST_ID AS REGST_ID , FN_GET_USRNM(A.REGST_ID) AS REGST_NM , TO_CHAR(A.REGST_DTTM, 'YYYYMMDDHH24MISS') AS REGST_DTTM , A.RVISN_ID AS RVISN_ID , FN_GET_USRNM(A.RVISN_ID) AS RVISN_NM , TO_CHAR(A.RVISN_DTTM, 'YYYYMMDDHH24MMSS') AS RVISN_DTTM FROM MSP_CHRG_PRMT A WHERE #{searchBaseDate} BETWEEN A.STRT_DT AND A.END_DT
AND UPPER(A.PRMT_NM) LIKE '%' || UPPER( #{prmtNm} ) || '%'
AND A.ORGN_TYPE = #{orgnType}
AND A.REQ_BUY_TYPE = #{reqBuyType}
AND EXISTS (SELECT 1 FROM MSP_CHRG_PRMT_ONOFF WHERE PRMT_ID = A.PRMT_ID AND ON_OFF_TYPE = #{onOffType})
AND A.USG_YN = 'Y' ORDER BY A.REGST_DTTM DESC
